#!/usr/bin/env node
/**
 * poteau-gen.mjs — projen-discipline config generator.
 *
 * Reads poteau/manifest/poteau.manifest.json (the ONLY hand-edited file) and emits:
 *   .claude/settings.poteau.json   — the hook lattice wiring (merge into settings.json)
 *   .run/poteau/checksums.json     — sha256 of every generated file + every hook script
 *
 * Invariants (each has a demo assertion in test/run-demo.sh):
 *   PT-GEN-1  Generated files carry an @generated header and are checksummed.
 *   PT-GEN-2  Re-running gen over a hand-edited generated file REFUSES (exit 3, P401)
 *             unless --force. Drift is layer leakage: operational hands on
 *             collective-choice artifacts.
 *   PT-GEN-3  If the manifest mandates a council the runtime cannot honor
 *             (gate.council.honor_review_routing && no council runner configured),
 *             gen REFUSES TO COMPILE (exit 4, P301). Fail-closed beats silent
 *             downgrade to single-model — issue #30's fix, enforced at build time.
 */
import { readFileSync, writeFileSync, mkdirSync, existsSync, readdirSync } from 'node:fs';
import { createHash } from 'node:crypto';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const ROOT = process.env.POTEAU_ROOT ?? process.cwd();
const PKG = join(dirname(fileURLToPath(import.meta.url)), '..');
const sha = (b) => 'sha256:' + createHash('sha256').update(b).digest('hex');
const force = process.argv.includes('--force');
const fail = (code, ecode, msg) => { console.error(`${ecode}: ${msg}`); process.exit(code); };

const manifest = JSON.parse(readFileSync(join(PKG, 'manifest/poteau.manifest.json'), 'utf8'));

// ── PT-GEN-4: verify the runtime closure at COMPILE time (P302). The hooks depend on
// jq; tool-gate fails OPEN on parse failure by design (wide-open default), which means
// a missing jq silently disarms the custody surface at runtime. The correct posture is
// to refuse to arm a lattice whose dependencies are absent — verify the closure here,
// where failing closed costs nothing, instead of discovering it open in production.
// (Finding: 2026-06-12 demo run — jq absent → P402 denials silently became allows.)
import { spawnSync } from 'node:child_process';
if (spawnSync('jq', ['--version']).status !== 0)
  fail(5, 'P302', 'runtime dependency "jq" not found on PATH. The hook lattice cannot enforce ' +
    'without its parser, and tool-gate fails open without it — refusing to generate an armed ' +
    'config for a host that cannot honor it. Fix: install jq, then re-run gen.');


// ── PT-GEN-3: refuse-to-compile on unhonorable mandates (issue #30, at build time) ──
if (manifest.gate.council.honor_review_routing) {
  const runner = manifest.gate.council.runner ?? null; // wired in Phase 3 of PROMPT.md
  if (!runner && manifest.gate.council.on_unhonorable_mandate === 'refuse_to_compile') {
    if (!process.argv.includes('--allow-single-model'))
      fail(4, 'P301', 'manifest honors review_routing but no council.runner is configured. ' +
        'Refusing to compile a mandated surface this lattice cannot honor (fail-closed beats ' +
        'silent downgrade). Fix: set gate.council.runner, or pass --allow-single-model to ' +
        'RECORD the downgrade decision loudly (it will be stamped into settings and receipts).');
    console.error('P301-OVERRIDE: single-model downgrade RECORDED (loudest signal, not a quiet default).');
  }
}

// ── the hook lattice (the sandwich's inner layer) ──
const hook = (script) => [{ matcher: '', hooks: [{ type: 'command', command: `poteau/hooks/${script}` }] }];
const settings = {
  '//': '@generated by poteau-gen.mjs from poteau/manifest/poteau.manifest.json — DO NOT EDIT (PT-GEN-2). Merge "hooks" into .claude/settings.json or reference via includes.',
  '//generated_at': new Date().toISOString(),
  '//manifest_hash': sha(readFileSync(join(PKG, 'manifest/poteau.manifest.json'))),
  hooks: {
    UserPromptSubmit: hook('prompt-arm.sh'),
    PreToolUse: [
      { matcher: 'Write|Edit|MultiEdit', hooks: [{ type: 'command', command: 'poteau/hooks/tool-gate.sh' }] },
      { matcher: 'Bash', hooks: [{ type: 'command', command: 'poteau/hooks/tool-gate.sh' }] },
    ],
    PostToolUse: hook('move-record.sh'),
    Stop: hook('exit-gate.sh'),
    SubagentStop: hook('exit-gate.sh'),
    PreCompact: hook('compact-clew.sh'),
  },
  '//council_downgrade_recorded': manifest.gate.council.runner ? undefined
    : (process.argv.includes('--allow-single-model') ? 'single-model (P301 override)' : undefined),
};

// ── PT-GEN-2: drift detection before overwrite ──
const outPath = join(ROOT, '.claude/settings.poteau.json');
const csPath = join(ROOT, '.run/poteau/checksums.json');
if (existsSync(outPath) && existsSync(csPath) && !force) {
  const prev = JSON.parse(readFileSync(csPath, 'utf8'));
  const current = sha(readFileSync(outPath));
  if (prev.files?.['.claude/settings.poteau.json'] && prev.files['.claude/settings.poteau.json'] !== current)
    fail(3, 'P401', 'generated file .claude/settings.poteau.json was hand-edited since last gen ' +
      '(checksum drift). Operational hands on a collective-choice artifact. Edit the MANIFEST ' +
      'instead, or pass --force to overwrite and discard the drift.');
}

mkdirSync(dirname(outPath), { recursive: true });
mkdirSync(dirname(csPath), { recursive: true });
writeFileSync(outPath, JSON.stringify(settings, null, 2) + '\n');

// checksum every generated file AND every hook script (the law protecting the law:
// tool-gate.sh denies writes to these paths; this ledger detects out-of-band edits)
const files = { '.claude/settings.poteau.json': sha(readFileSync(outPath)) };
for (const f of readdirSync(join(PKG, 'hooks'))) files[`poteau/hooks/${f}`] = sha(readFileSync(join(PKG, 'hooks', f)));
for (const f of readdirSync(join(PKG, 'bin'))) files[`poteau/bin/${f}`] = sha(readFileSync(join(PKG, 'bin', f)));
writeFileSync(csPath, JSON.stringify({ generated_at: new Date().toISOString(), files }, null, 2) + '\n');
console.log(`poteau-gen: wrote ${outPath} and checksummed ${Object.keys(files).length} files.`);
